const config = {
  "previewFeatures": [
    "driverAdapters"
  ],
  "clientVersion": "7.4.2",
  "engineVersion": "94a226be1cf2967af2541cca5529f0f7ba866919",
  "activeProvider": "postgresql",
  "inlineSchema": "// Zoho ERP Prisma Schema\n// Comprehensive ERP system with branches, warehouses, inventory, sales, and logistics\n// UUID for all primary keys, timestamps on all entities\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n// backend/prisma/schema.prisma\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  output          = \"../src/generated\"\n  previewFeatures = [\"driverAdapters\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================================================\n// ENUMS\n// ============================================================================\n\nenum InventoryStatus {\n  in_stock\n  low_stock\n  out_of_stock\n  discontinued\n\n  @@map(\"inventory_status\")\n}\n\nenum ProductType {\n  physical\n  digital\n  service\n\n  @@map(\"product_type\")\n}\n\nenum ProductStatus {\n  active\n  inactive\n  discontinued\n\n  @@map(\"product_status\")\n}\n\nenum SalesStatus {\n  draft\n  pending\n  confirmed\n  shipped\n  delivered\n  cancelled\n  returned\n\n  @@map(\"sales_status\")\n}\n\nenum SalesDocumentType {\n  DRAFT\n  QUOTE\n  INVOICE\n  CREDIT_NOTE\n\n  @@map(\"sales_document_type\")\n}\n\nenum SalesDocumentStatus {\n  DRAFT\n  SENT\n  PARTIALLY_PAID\n  PAID\n  VOID\n  CONVERTED\n  CREDITED\n  PARTIALLY_CREDITED\n\n  @@map(\"sales_document_status\")\n}\n\n// Re-using the existing PaymentMethod enum\n\nenum PaymentStatus {\n  UNPAID\n  PARTIALLY_PAID\n  PAID\n  REFUNDED\n\n  @@map(\"payment_status\")\n}\n\nenum DeliveryStatus {\n  pending\n  assigned\n  in_transit\n  delivered\n  failed\n  rescheduled\n\n  @@map(\"delivery_status\")\n}\n\nenum TransactionType {\n  income\n  expense\n  transfer\n  adjustment\n\n  @@map(\"transaction_type\")\n}\n\nenum PayrollStatus {\n  draft\n  submitted\n  approved\n  paid\n  reversed\n\n  @@map(\"payroll_status\")\n}\n\nenum PaymentMethod {\n  cash\n  card\n  mpesa\n  cheque\n  bank_transfer\n\n  @@map(\"payment_method\")\n}\n\nenum CashierSessionStatus {\n  OPEN\n  CLOSED\n  DISCREPANCY\n  RECONCILED\n\n  @@map(\"cashier_session_status\")\n}\n\nenum MovementType {\n  INBOUND\n  OUTBOUND\n  TRANSFER_IN\n  TRANSFER_OUT\n  ADJUSTMENT\n\n  @@map(\"movement_type\")\n}\n\nenum TransferStatus {\n  PENDING\n  IN_TRANSIT\n  PENDING_RECEIPT\n  COMPLETED\n  CANCELLED\n  DISCREPANCY\n\n  @@map(\"transfer_status\")\n}\n\nenum JournalType {\n  sale\n  purchase\n  cash\n  bank\n  general\n\n  @@map(\"journal_type\")\n}\n\nenum FiscalStatus {\n  open\n  closed\n  locked\n\n  @@map(\"fiscal_status\")\n}\n\nenum AuditAction {\n  CREATE\n  UPDATE\n  DELETE\n}\n\nenum ApprovalType {\n  VENDOR_CHANGE\n  PO_APPROVAL\n  TRANSFER_APPROVAL\n  PRICE_ADJUSTMENT\n  STOCK_ADJUSTMENT\n\n  @@map(\"approval_type\")\n}\n\nenum ApprovalStatus {\n  PENDING\n  APPROVED\n  REJECTED\n\n  @@map(\"approval_status\")\n}\n\n// ============================================================================\n// CORE ORGANIZATION MODELS\n// ============================================================================\n\n/// Users/Employees\nmodel User {\n  id           String  @id @default(cuid())\n  email        String  @unique\n  passwordHash String  @map(\"password\")\n  name         String\n  phone        String?\n  role         String  @default(\"warehouse_staff\") // cashier, warehouse_staff, driver, manager, admin\n\n  // Branch assignment\n  branchId String?\n  branch   Branch? @relation(fields: [branchId], references: [id], onDelete: SetNull)\n\n  // Relations\n  payrollRecords        Payroll[]\n  deliveries            Delivery[]         @relation(\"DriverDeliveries\")\n  createdSalesDocuments SalesDocument[]\n  createdPayments       Payment[]\n  transfers             EmployeeTransfer[]\n  cashierSessions       CashierSession[]\n  // Leave Management\n  leaveAllocations      LeaveAllocation[]\n  leaveRequests         LeaveRequest[]\n\n  // Recruitment\n  interviews Interview[] @relation(\"Interviewer\")\n\n  // Performance\n  goals            Goal[]\n  evaluations      PerformanceEvaluation[] @relation(\"Evaluatee\")\n  givenEvaluations PerformanceEvaluation[] @relation(\"Evaluator\")\n  developmentPlans DevelopmentPlan[]\n\n  // RBAC Relations\n  roles RoleAssignment[]\n\n  // Benefits\n  benefitEnrollments BenefitEnrollment[]\n\n  // Fiscal Period Locking\n  lockedPeriods           FiscalPeriod[]    @relation(\"LockedPeriods\")\n  auditLogs               AuditLog[]\n  requestedPurchaseOrders PurchaseOrder[]   @relation(\"RequestedByPO\")\n  approvedPurchaseOrders  PurchaseOrder[]   @relation(\"ApprovedByPO\")\n  requestedApprovals      ApprovalRequest[] @relation(\"RequestedApprovals\")\n  approvedApprovals       ApprovalRequest[] @relation(\"ApprovedApprovals\")\n\n  createdTransfers  StockTransfer[] @relation(\"CreatedTransfers\")\n  receivedTransfers StockTransfer[] @relation(\"ReceivedTransfers\")\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([branchId])\n  @@index([email])\n  @@index([isActive])\n  @@map(\"users\")\n}\n\n/// Branches/Locations\nmodel Branch {\n  id      String  @id @default(cuid())\n  code    String  @unique\n  name    String\n  city    String\n  address String?\n  phone   String?\n\n  // Relations\n  users             User[]\n  warehouses        Warehouse[]\n  branchInventory   BranchInventory[] // Link to product inventories for this branch\n  salesDocuments    SalesDocument[]\n  documentSequences DocumentSequence[]\n  cashierSessions   CashierSession[]\n  transfersFrom     EmployeeTransfer[] @relation(\"TransfersFrom\")\n  transfersTo       EmployeeTransfer[] @relation(\"TransfersTo\")\n  purchaseOrders    PurchaseOrder[]\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([code])\n  @@index([isActive])\n  @@map(\"branches\")\n}\n\n/// Employee Transfers\nmodel EmployeeTransfer {\n  id            String    @id @default(cuid())\n  userId        String\n  user          User      @relation(fields: [userId], references: [id], onDelete: Restrict)\n  fromBranchId  String?\n  fromBranch    Branch?   @relation(\"TransfersFrom\", fields: [fromBranchId], references: [id], onDelete: SetNull)\n  toBranchId    String\n  toBranch      Branch    @relation(\"TransfersTo\", fields: [toBranchId], references: [id], onDelete: Restrict)\n  fromRole      String?\n  toRole        String\n  transferDate  DateTime  @default(now())\n  effectiveDate DateTime\n  reason        String?\n  approvedBy    String?\n  approvedAt    DateTime?\n  notes         String?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  @@index([userId])\n  @@index([fromBranchId])\n  @@index([toBranchId])\n  @@index([transferDate])\n  @@map(\"employee_transfers\")\n}\n\n/// Warehouses/Storage Locations\nmodel Warehouse {\n  id       String @id @default(cuid())\n  code     String @unique\n  name     String\n  location String\n  capacity Int // Total storage capacity in units\n\n  // Branch relationship\n  branchId String\n  branch   Branch @relation(fields: [branchId], references: [id], onDelete: Cascade)\n\n  // Relations\n  inventory       Inventory[]\n  stockMovements  StockMovement[]\n  sourceTransfers StockTransfer[] @relation(\"SourceTransfers\")\n  targetTransfers StockTransfer[] @relation(\"TargetTransfers\")\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([branchId])\n  @@index([code])\n  @@index([isActive])\n  @@map(\"warehouses\")\n}\n\n// ============================================================================\n// PRODUCT & INVENTORY MODELS\n// ============================================================================\n\n/// Products\nmodel Product {\n  id          String  @id @default(cuid())\n  sku         String  @unique\n  upc         String? @unique // UPC barcode\n  barcode     String? // Additional barcode field\n  name        String\n  description String?\n\n  // Classification\n  category     String?\n  subcategory  String?\n  product_type ProductType @default(physical)\n\n  // Pricing - Global/Master Data\n  cost_price Float // Cost to company\n  unit_price Float // Base selling price\n  tax_rate   Float @default(0.16) // Default 16% VAT\n\n  // Unit of measurement - Global\n  unit_of_measurement String @default(\"pcs\") // units, kg, lbs, etc\n\n  // Physical properties\n  weight         Float? // Product weight\n  weight_unit    String? @default(\"kg\") // kg, lbs, etc\n  length         Float? // Dimensions\n  width          Float?\n  height         Float?\n  dimension_unit String? @default(\"cm\") // cm, inches, etc\n\n  // Product media\n  image_url String? // Product image URL\n\n  // Supplier information\n  vendorId             String?\n  vendor               Vendor? @relation(fields: [vendorId], references: [id])\n  supplier_part_number String?\n  lead_time_days       Int? // Lead time in days\n\n  // Status - Global\n  status ProductStatus @default(active)\n\n  // Relations\n  branchInventory    BranchInventory[] // Link to branch-specific inventory\n  inventory          Inventory[]\n  salesDocumentItems SalesDocumentItem[]\n  stockMovements     StockMovement[]\n  transferItems      TransferItem[]\n  purchaseOrderItems PurchaseOrderItem[]\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([sku])\n  @@index([upc])\n  @@index([barcode])\n  @@index([category])\n  @@index([status])\n  @@index([isActive])\n  @@map(\"products\")\n}\n\n/// Branch Inventory - Aggregated quantities and settings per branch\n/// This is the junction table that separates master data (Product) from local data (quantities per branch)\nmodel BranchInventory {\n  id String @id @default(cuid())\n\n  // Foreign Keys\n  productId String\n  branchId  String\n\n  // Branch-specific inventory data\n  quantity         Int             @default(0) // Total quantity across all warehouses in this branch\n  reorder_level    Int             @default(10) // Branch-specific reorder point\n  reorder_quantity Int             @default(20) // Branch-specific reorder amount\n  reserved         Int             @default(0) // Reserved for pending sales in this branch\n  available        Int             @default(0) // quantity - reserved\n  status           InventoryStatus @default(in_stock)\n\n  // Local pricing override (optional)\n  local_price  Float? // Override global unit_price for this branch\n  bin_location String? // Where in this branch's warehouse is it stored?\n\n  last_counted DateTime?\n\n  // Relations\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  branch  Branch  @relation(fields: [branchId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Ensure only one inventory record per product per branch\n  @@unique([productId, branchId])\n  @@index([productId])\n  @@index([branchId])\n  @@index([status])\n  @@map(\"branch_inventory\")\n}\n\n/// Inventory - Links Products to Warehouses\nmodel Inventory {\n  id           String          @id @default(cuid())\n  quantity     Int             @default(0)\n  reserved     Int             @default(0) // Reserved for pending sales\n  available    Int             @default(0) // quantity - reserved\n  status       InventoryStatus @default(in_stock)\n  last_counted DateTime?\n\n  // Foreign keys\n  productId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  warehouseId String\n  warehouse   Warehouse @relation(fields: [warehouseId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([productId, warehouseId])\n  @@index([productId])\n  @@index([warehouseId])\n  @@index([status])\n  @@map(\"inventory\")\n}\n\n// ============================================================================\n// STOCK MOVEMENT MODELS\n// ============================================================================\n\n/// Stock Movements - Audit trail for all inventory changes\nmodel StockMovement {\n  id          String         @id @default(cuid())\n  type        MovementType\n  quantity    Int\n  productId   String\n  product     Product        @relation(fields: [productId], references: [id])\n  warehouseId String\n  warehouse   Warehouse      @relation(fields: [warehouseId], references: [id])\n  salesId     String?\n  sales       SalesDocument? @relation(fields: [salesId], references: [id])\n  transferId  String?\n  transfer    StockTransfer? @relation(fields: [transferId], references: [id])\n  reference   String? // e.g., \"Reason for adjustment\"\n  createdById String\n  createdAt   DateTime       @default(now())\n\n  @@index([productId, warehouseId])\n  @@index([type])\n  @@index([createdAt])\n  @@index([transferId])\n  @@map(\"stock_movements\")\n}\n\n/// Stock Transfers - Transfer stock between warehouses\nmodel StockTransfer {\n  id              String          @id @default(cuid())\n  transferNo      String          @unique\n  status          TransferStatus  @default(PENDING)\n  sourceId        String\n  sourceWarehouse Warehouse       @relation(\"SourceTransfers\", fields: [sourceId], references: [id])\n  targetId        String\n  targetWarehouse Warehouse       @relation(\"TargetTransfers\", fields: [targetId], references: [id])\n  items           TransferItem[]\n  stockMovements  StockMovement[]\n  notes           String?\n\n  // Logistics info\n  truckRegNo    String?\n  driverName    String?\n  attendantName String?\n\n  // Received info\n  receivedAt   DateTime?\n  receivedById String?\n  receivedBy   User?     @relation(\"ReceivedTransfers\", fields: [receivedById], references: [id])\n\n  createdById String\n  createdBy   User     @relation(\"CreatedTransfers\", fields: [createdById], references: [id])\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([status])\n  @@index([sourceId])\n  @@index([targetId])\n  @@index([createdAt])\n  @@map(\"stock_transfers\")\n}\n\n/// Transfer Items - Line items within a stock transfer\nmodel TransferItem {\n  id         String        @id @default(cuid())\n  quantity   Int\n  productId  String\n  product    Product       @relation(fields: [productId], references: [id])\n  transferId String\n  transfer   StockTransfer @relation(fields: [transferId], references: [id], onDelete: Cascade)\n\n  @@index([transferId])\n  @@index([productId])\n  @@map(\"transfer_items\")\n}\n\n// ============================================================================\n// SALES MODELS\n// ============================================================================\n// NOTE: Legacy Sales and SalesItem models have been removed.\n// All POS operations now use the modern SalesDocument and SalesDocumentItem models.\n// Cashier session management implementation - STEP 1: Legacy model removal.\n// ============================================================================\n\n// ============================================================================\n// CUSTOMER & SALES DOCUMENT MODELS (V2)\n// ============================================================================\n\n/// Customers/Clients of the business\nmodel Customer {\n  id      String  @id @default(cuid())\n  name    String\n  email   String? @unique\n  phone   String?\n  address String?\n  taxId   String? @map(\"tax_id\") // Business tax ID, VAT number, etc.\n\n  // Relations\n  salesDocuments SalesDocument[]\n  payments       Payment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([email])\n  @@index([phone])\n  @@map(\"customers\")\n}\n\n/// Unified model for Drafts, Quotes, Invoices, and Credit Notes\nmodel SalesDocument {\n  id         String              @id @default(cuid())\n  documentId String // Branch-scoped, sequential ID (e.g., INV-0001)\n  type       SalesDocumentType\n  status     SalesDocumentStatus\n\n  // Lifecycle tracking\n  sourceDocumentId String?        @unique @map(\"source_document_id\")\n  sourceDocument   SalesDocument? @relation(\"DocumentLifecycle\", fields: [sourceDocumentId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  childDocument    SalesDocument? @relation(\"DocumentLifecycle\")\n\n  // Foreign keys\n  branchId   String\n  branch     Branch    @relation(fields: [branchId], references: [id], onDelete: Restrict)\n  customerId String?\n  customer   Customer? @relation(fields: [customerId], references: [id], onDelete: SetNull)\n\n  createdById String\n  createdBy   User   @relation(fields: [createdById], references: [id], onDelete: Restrict)\n\n  // Cashier Session (POS transactions)\n  sessionId String?\n  session   CashierSession? @relation(fields: [sessionId], references: [id], onDelete: SetNull)\n\n  // Financials\n  items    SalesDocumentItem[]\n  subtotal Float\n  discount Float               @default(0)\n  tax      Float\n  total    Float\n  notes    String?\n  terms    String? // Payment terms, etc.\n\n  // Payment Status (for Invoices and Credit Notes)\n  paymentStatus PaymentStatus? @map(\"payment_status\")\n  paidAmount    Float          @default(0)\n  balance       Float\n\n  // Dates\n  issueDate DateTime  @default(now()) @map(\"issue_date\")\n  dueDate   DateTime? @map(\"due_date\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  payments       Payment[]\n  stockMovements StockMovement[]\n\n  @@unique([branchId, documentId])\n  @@index([type])\n  @@index([status])\n  @@index([branchId])\n  @@index([customerId])\n  @@index([createdById])\n  @@index([sessionId])\n  @@index([issueDate])\n  @@map(\"sales_documents\")\n}\n\n/// Line items for SalesDocuments\nmodel SalesDocumentItem {\n  id String @id @default(cuid())\n\n  // Foreign keys\n  salesDocumentId String\n  salesDocument   SalesDocument @relation(fields: [salesDocumentId], references: [id], onDelete: Cascade)\n\n  productId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Restrict)\n\n  // Snapshot of product details at time of creation\n  description String\n  quantity    Float\n  unitPrice   Float  @map(\"unit_price\")\n  taxRate     Float  @map(\"tax_rate\")\n  discount    Float  @default(0) // Line item discount amount\n  subtotal    Float // quantity * unitPrice\n  taxAmount   Float  @map(\"tax_amount\")\n  total       Float // subtotal - discount + taxAmount\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([salesDocumentId])\n  @@index([productId])\n  @@map(\"sales_document_items\")\n}\n\n/// Tracks payments made against Invoices\nmodel Payment {\n  id String @id @default(cuid())\n\n  // Foreign keys\n  salesDocumentId String\n  salesDocument   SalesDocument @relation(fields: [salesDocumentId], references: [id], onDelete: Restrict)\n  customerId      String?\n  customer        Customer?     @relation(fields: [customerId], references: [id], onDelete: SetNull)\n\n  // Payment details\n  amount      Float\n  paymentDate DateTime      @default(now()) @map(\"payment_date\")\n  method      PaymentMethod\n  reference   String? // e.g., Cheque number, transaction ID\n  createdById String\n  createdBy   User          @relation(fields: [createdById], references: [id], onDelete: Restrict)\n  notes       String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([salesDocumentId])\n  @@index([customerId])\n  @@index([method])\n  @@index([paymentDate])\n  @@map(\"payments\")\n}\n\n/// Tracks the next document number for each type per branch\nmodel DocumentSequence {\n  id         String            @id @default(cuid())\n  branchId   String\n  branch     Branch            @relation(fields: [branchId], references: [id], onDelete: Cascade)\n  type       SalesDocumentType\n  prefix     String\n  nextNumber Int               @default(1) @map(\"next_number\")\n\n  @@unique([branchId, type])\n  @@index([branchId])\n  @@map(\"document_sequences\")\n}\n\n// ============================================================================\n// CASHIER SESSION MANAGEMENT\n// ============================================================================\n\n/// Cashier Sessions for shift management and cash reconciliation\nmodel CashierSession {\n  id        String @id @default(cuid())\n  sessionNo String @unique\n\n  // Relationships\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Restrict)\n\n  branchId String\n  branch   Branch @relation(fields: [branchId], references: [id], onDelete: Restrict)\n\n  sales SalesDocument[]\n\n  // Session Status\n  status CashierSessionStatus @default(OPEN)\n\n  // Opening balances\n  openingBalance Float @default(0) @map(\"opening_balance\")\n\n  // Closing details\n  closingBalance Float? @map(\"closing_balance\")\n  expectedCash   Float? @map(\"expected_cash\")\n  actualCash     Float? @map(\"actual_cash\")\n  cashVariance   Float? @map(\"cash_variance\")\n\n  // Sales summary\n  totalSalesCount  Int   @default(0) @map(\"total_sales_count\")\n  totalSalesAmount Float @default(0) @map(\"total_sales_amount\")\n\n  // Payment method breakdown\n  totalCashReceived  Float @default(0) @map(\"total_cash_received\")\n  totalCardReceived  Float @default(0) @map(\"total_card_received\")\n  totalMpesaReceived Float @default(0) @map(\"total_mpesa_received\")\n  totalOtherReceived Float @default(0) @map(\"total_other_received\")\n\n  // Timestamps\n  openedAt     DateTime  @default(now()) @map(\"opened_at\")\n  closedAt     DateTime? @map(\"closed_at\")\n  reconciledAt DateTime? @map(\"reconciled_at\")\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([branchId, sessionNo])\n  @@index([userId])\n  @@index([branchId])\n  @@index([status])\n  @@index([openedAt])\n  @@index([sessionNo])\n  @@map(\"cashier_sessions\")\n}\n\n// ============================================================================\n// PURCHASING & VENDOR MODELS\n// ============================================================================\n\nenum PurchaseOrderStatus {\n  DRAFT\n  SUBMITTED\n  APPROVED\n  PARTIALLY_RECEIVED\n  RECEIVED\n  CLOSED\n  CANCELLED\n\n  @@map(\"purchase_order_status\")\n}\n\n/// Vendors/Suppliers\nmodel Vendor {\n  id      String  @id @default(cuid())\n  code    String  @unique\n  name    String\n  email   String?\n  phone   String?\n  address String?\n  taxId   String? @map(\"tax_id\")\n  website String?\n\n  // Relations\n  purchaseOrders PurchaseOrder[]\n  products       Product[]\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([code])\n  @@index([name])\n  @@index([isActive])\n  @@map(\"vendors\")\n}\n\n/// Purchase Orders\nmodel PurchaseOrder {\n  id       String              @id @default(cuid())\n  poNumber String              @unique @map(\"po_number\")\n  status   PurchaseOrderStatus @default(DRAFT)\n\n  // Foreign keys\n  vendorId String\n  vendor   Vendor @relation(fields: [vendorId], references: [id], onDelete: Restrict)\n\n  branchId String\n  branch   Branch @relation(fields: [branchId], references: [id], onDelete: Restrict)\n\n  requestedById String\n  requestedBy   User   @relation(\"RequestedByPO\", fields: [requestedById], references: [id], onDelete: Restrict)\n\n  approvedById String?\n  approvedBy   User?   @relation(\"ApprovedByPO\", fields: [approvedById], references: [id], onDelete: SetNull)\n\n  // Financials\n  subtotal Float @default(0)\n  tax      Float @default(0)\n  total    Float @default(0)\n\n  // Details\n  items                PurchaseOrderItem[]\n  notes                String?\n  expectedDeliveryDate DateTime?           @map(\"expected_delivery_date\")\n\n  // Lifecycle\n  submittedAt DateTime?\n  approvedAt  DateTime?\n  closedAt    DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([poNumber])\n  @@index([vendorId])\n  @@index([branchId])\n  @@index([status])\n  @@map(\"purchase_orders\")\n}\n\n/// Approval Requests for high-risk actions\nmodel ApprovalRequest {\n  id            String         @id @default(cuid())\n  type          ApprovalType\n  status        ApprovalStatus @default(PENDING)\n  requestedById String\n  requestedBy   User           @relation(\"RequestedApprovals\", fields: [requestedById], references: [id])\n  approvedById  String?\n  approvedBy    User?          @relation(\"ApprovedApprovals\", fields: [approvedById], references: [id])\n  data          Json // Snapshot of requested changes or metadata\n  referenceId   String? // ID of the entity being approved (e.g., productId)\n  notes         String?\n  createdAt     DateTime       @default(now())\n  updatedAt     DateTime       @updatedAt\n\n  @@index([type])\n  @@index([status])\n  @@index([requestedById])\n  @@map(\"approval_requests\")\n}\n\n/// Purchase Order Line Items\nmodel PurchaseOrderItem {\n  id              String        @id @default(cuid())\n  purchaseOrderId String\n  purchaseOrder   PurchaseOrder @relation(fields: [purchaseOrderId], references: [id], onDelete: Cascade)\n\n  productId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Restrict)\n\n  // Snapshot of item details\n  quantity  Int\n  unitPrice Float @map(\"unit_price\")\n  subtotal  Float // quantity * unitPrice\n\n  // Tracking\n  receivedQuantity Int @default(0) @map(\"received_quantity\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([purchaseOrderId])\n  @@index([productId])\n  @@map(\"purchase_order_items\")\n}\n\n// ============================================================================\n// LOGISTICS MODELS\n// ============================================================================\n\n/// Trucks/Vehicles\nmodel Truck {\n  id            String  @id @default(cuid())\n  registration  String  @unique\n  model         String\n  capacity      Int // Capacity in units\n  license_plate String? @unique\n\n  // Relations\n  deliveries Delivery[]\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([registration])\n  @@index([isActive])\n  @@map(\"trucks\")\n}\n\n/// Deliveries\nmodel Delivery {\n  id          String         @id @default(cuid())\n  delivery_no String         @unique\n  status      DeliveryStatus @default(pending)\n\n  // Relationships\n  driverId String\n  driver   User   @relation(\"DriverDeliveries\", fields: [driverId], references: [id], onDelete: Restrict)\n\n  truckId String\n  truck   Truck  @relation(fields: [truckId], references: [id], onDelete: Restrict)\n\n  // Delivery details\n  destination  String\n  estimated_km Int?\n  actual_km    Int?\n\n  // Timestamps\n  scheduled_date DateTime?\n  picked_up_at   DateTime?\n  delivered_at   DateTime?\n  notes          String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([driverId])\n  @@index([truckId])\n  @@index([status])\n  @@index([delivery_no])\n  @@map(\"deliveries\")\n}\n\n// ============================================================================\n// FINANCIAL MODELS\n// ============================================================================\n\n/// Finance Transactions - Enhanced with category and date filtering\nmodel FinanceTransaction {\n  id              String          @id @default(cuid())\n  type            TransactionType\n  reference_no    String          @unique\n  description     String\n  amount          Float\n  category        String? // e.g., \"food\", \"utilities\", \"shopping\", \"payroll\", \"income\", \"sales\", \"services\"\n  transactionDate DateTime        @default(now()) // Separate from createdAt for historical data\n\n  // Relationships\n  payrollId String?\n  payroll   Payroll? @relation(fields: [payrollId], references: [id], onDelete: SetNull)\n\n  // Metadata\n  payment_method String? // cash, check, card, transfer\n  reference_doc  String? // Invoice number, receipt number, etc.\n  notes          String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([type])\n  @@index([category])\n  @@index([transactionDate])\n  @@index([reference_no])\n  @@index([payrollId])\n  @@map(\"finance_transactions\")\n}\n\n/// Savings Goals - Track financial goals with progress\nmodel SavingsGoal {\n  id            String    @id @default(cuid())\n  name          String\n  description   String?\n  targetAmount  Float\n  currentAmount Float     @default(0)\n  deadline      DateTime?\n  status        String    @default(\"active\") // \"active\" or \"completed\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([createdAt])\n  @@map(\"savings_goals\")\n}\n\n/// Daily Spending Limit - Track daily spending against configured limit\nmodel DailySpendingLimit {\n  id    String   @id @default(cuid())\n  limit Float    @default(50000) // Default 50,000 KES\n  date  DateTime\n  spent Float    @default(0)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([date])\n  @@index([date])\n  @@map(\"daily_spending_limits\")\n}\n\n// ============================================================================\n// PAYROLL MODELS\n// ============================================================================\n\n/// Payroll Records\nmodel Payroll {\n  id         String        @id @default(cuid())\n  payroll_no String        @unique\n  status     PayrollStatus @default(draft)\n\n  // Relationships\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Restrict)\n\n  // Compensation\n  base_salary Float\n  allowances  Float @default(0)\n  deductions  Float @default(0)\n  net_salary  Float\n\n  // Dates\n  period_start DateTime\n  period_end   DateTime\n  paid_date    DateTime?\n\n  // Finance link\n  transactions FinanceTransaction[]\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([status])\n  @@index([payroll_no])\n  @@map(\"payroll\")\n}\n\n// ============================================================================\n// INDEXES & CONSTRAINTS\n// ============================================================================\n\n// Additional composite indexes for common queries\n// Note: Many single-field indexes are defined inline with @index decorators\n\n// ============================================================================\n// ENHANCED FINANCIAL MODELS\n// ============================================================================\n\n/// Chart of Accounts - Foundation for all financial tracking\nmodel ChartOfAccount {\n  id           String           @id @default(cuid())\n  account_code String           @unique\n  account_name String\n  account_type AccountType\n  parent_id    String?\n  parent       ChartOfAccount?  @relation(\"AccountHierarchy\", fields: [parent_id], references: [id])\n  children     ChartOfAccount[] @relation(\"AccountHierarchy\")\n\n  category    String\n  subcategory String?\n\n  is_active Boolean @default(true)\n  is_system Boolean @default(false)\n\n  current_balance Float @default(0)\n\n  journal_entries JournalEntry[]\n  budgets         Budget[] // existing\n  bank_statements BankStatement[] // Add this\n\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([account_code])\n  @@index([account_type])\n  @@index([category])\n  @@map(\"chart_of_accounts\")\n}\n\n/// Journals - Categorize transactions\nmodel Journal {\n  id   String      @id @default(cuid())\n  code String      @unique // e.g., \"MISC\", \"SALE\", \"PURCH\"\n  name String\n  type JournalType\n\n  entries JournalEntry[]\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"journals\")\n}\n\n/// Fiscal Year - Formal accounting years\nmodel FiscalYear {\n  id        String       @id @default(cuid())\n  name      String // e.g., \"2024\"\n  startDate DateTime     @map(\"start_date\")\n  endDate   DateTime     @map(\"end_date\")\n  status    FiscalStatus @default(open)\n\n  periods FiscalPeriod[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"fiscal_years\")\n}\n\n/// Fiscal Period - Monthly/Quarterly divisions\nmodel FiscalPeriod {\n  id           String       @id @default(cuid())\n  fiscalYearId String       @map(\"fiscal_year_id\")\n  fiscalYear   FiscalYear   @relation(fields: [fiscalYearId], references: [id])\n  name         String // e.g., \"Jan 2024\"\n  startDate    DateTime     @map(\"start_date\")\n  endDate      DateTime     @map(\"end_date\")\n  status       FiscalStatus @default(open)\n\n  // Locking fields\n  isLocked   Boolean   @default(false)\n  lockedAt   DateTime?\n  lockedById String?\n  lockedBy   User?     @relation(\"LockedPeriods\", fields: [lockedById], references: [id])\n\n  entries JournalEntry[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([lockedById])\n  @@map(\"fiscal_periods\")\n}\n\n/// Journal Entries - Double-entry bookkeeping\nmodel JournalEntry {\n  id         String   @id @default(cuid())\n  entry_no   String   @unique\n  entry_date DateTime @default(now())\n\n  account_id String\n  account    ChartOfAccount @relation(fields: [account_id], references: [id])\n\n  debit  Float @default(0)\n  credit Float @default(0)\n\n  reference_type String?\n  reference_id   String?\n\n  batch_id String?\n\n  journal_id String?\n  journal    Journal? @relation(fields: [journal_id], references: [id])\n\n  period_id String?\n  period    FiscalPeriod? @relation(fields: [period_id], references: [id])\n\n  description String\n  notes       String?\n\n  is_reconciled   Boolean   @default(false)\n  reconciled_date DateTime?\n\n  // Link to Bank Statement Line (reconciliation)\n  statement_line BankStatementLine? // Add this (optional inverse relation)\n\n  created_by    String\n  approved_by   String?\n  approved_date DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([account_id])\n  @@index([entry_no])\n  @@index([entry_date])\n  @@index([batch_id])\n  @@index([journal_id])\n  @@index([period_id])\n  @@index([reference_type, reference_id])\n  @@map(\"journal_entries\")\n}\n\n/// Budget Management\nmodel Budget {\n  id          String @id @default(cuid())\n  budget_name String\n  fiscal_year Int\n\n  account_id String\n  account    ChartOfAccount @relation(fields: [account_id], references: [id])\n\n  period_type  PeriodType @default(monthly)\n  period_start DateTime\n  period_end   DateTime\n\n  budgeted_amount  Float\n  actual_amount    Float @default(0)\n  variance         Float @default(0)\n  variance_percent Float @default(0)\n\n  status BudgetStatus @default(draft)\n\n  created_by    String\n  approved_by   String?\n  approved_date DateTime?\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([account_id, fiscal_year, period_start])\n  @@index([account_id])\n  @@index([fiscal_year])\n  @@index([status])\n  @@map(\"budgets\")\n}\n\n/// Bank Reconciliation Models\n\nmodel BankStatement {\n  id         String         @id @default(cuid())\n  account_id String\n  account    ChartOfAccount @relation(fields: [account_id], references: [id])\n\n  filename    String\n  upload_date DateTime @default(now())\n  uploaded_by String\n\n  start_date DateTime?\n  end_date   DateTime?\n\n  status String @default(\"pending\") // pending, reconciled\n\n  transactions BankStatementLine[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([account_id])\n  @@map(\"bank_statements\")\n}\n\nmodel BankStatementLine {\n  id           String        @id @default(cuid())\n  statement_id String\n  statement    BankStatement @relation(fields: [statement_id], references: [id], onDelete: Cascade)\n\n  date        DateTime\n  description String\n  amount      Float // Positive = Deposit, Negative = Withdrawal\n  reference   String?\n\n  is_reconciled   Boolean   @default(false)\n  reconciled_date DateTime?\n\n  // Link to system Journal Entry when matched\n  journal_entry_id String?       @unique\n  journal_entry    JournalEntry? @relation(fields: [journal_entry_id], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([statement_id])\n  @@index([date])\n  @@index([amount])\n  @@map(\"bank_statement_lines\")\n}\n\n/// Accounts Receivable\nmodel AccountReceivable {\n  id         String @id @default(cuid())\n  invoice_no String @unique\n\n  customer_name  String\n  customer_email String?\n  customer_phone String?\n\n  total_amount Float\n  paid_amount  Float @default(0)\n  balance      Float\n\n  invoice_date DateTime  @default(now())\n  due_date     DateTime\n  paid_date    DateTime?\n\n  status     ARStatus @default(outstanding)\n  aging_days Int      @default(0)\n\n  payments ARPayment[]\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([invoice_no])\n  @@index([customer_name])\n  @@index([status])\n  @@index([due_date])\n  @@map(\"accounts_receivable\")\n}\n\n/// AR Payments\nmodel ARPayment {\n  id         String @id @default(cuid())\n  payment_no String @unique\n\n  ar_id              String\n  account_receivable AccountReceivable @relation(fields: [ar_id], references: [id])\n\n  amount         Float\n  payment_method PaymentMethod\n  payment_date   DateTime      @default(now())\n\n  bank_name      String?\n  check_no       String?\n  transaction_id String?\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([ar_id])\n  @@index([payment_no])\n  @@index([payment_date])\n  @@map(\"ar_payments\")\n}\n\n/// Accounts Payable\nmodel AccountPayable {\n  id      String @id @default(cuid())\n  bill_no String @unique\n\n  vendor_name  String\n  vendor_email String?\n  vendor_phone String?\n\n  total_amount Float\n  paid_amount  Float @default(0)\n  balance      Float\n\n  bill_date DateTime  @default(now())\n  due_date  DateTime\n  paid_date DateTime?\n\n  status     APStatus @default(outstanding)\n  aging_days Int      @default(0)\n\n  payments APPayment[]\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([bill_no])\n  @@index([vendor_name])\n  @@index([status])\n  @@index([due_date])\n  @@map(\"accounts_payable\")\n}\n\n/// AP Payments\nmodel APPayment {\n  id         String @id @default(cuid())\n  payment_no String @unique\n\n  ap_id           String\n  account_payable AccountPayable @relation(fields: [ap_id], references: [id])\n\n  amount         Float\n  payment_method PaymentMethod\n  payment_date   DateTime      @default(now())\n\n  bank_name      String?\n  check_no       String?\n  transaction_id String?\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([ap_id])\n  @@index([payment_no])\n  @@index([payment_date])\n  @@map(\"ap_payments\")\n}\n\n/// Bank Accounts & Treasury\nmodel BankAccount {\n  id             String  @id @default(cuid())\n  account_name   String\n  account_number String  @unique\n  bank_name      String\n  branch         String?\n\n  account_type BankAccountType @default(checking)\n  currency     String          @default(\"KES\")\n\n  current_balance   Float @default(0)\n  available_balance Float @default(0)\n\n  overdraft_limit Float @default(0)\n\n  is_active Boolean @default(true)\n\n  transactions BankTransaction[]\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([account_number])\n  @@index([bank_name])\n  @@map(\"bank_accounts\")\n}\n\n/// Bank Transactions\nmodel BankTransaction {\n  id             String @id @default(cuid())\n  transaction_no String @unique\n\n  bank_account_id String\n  bank_account    BankAccount @relation(fields: [bank_account_id], references: [id])\n\n  transaction_type TransactionType\n  amount           Float\n  balance_after    Float\n\n  description  String\n  reference_no String?\n\n  category String?\n\n  is_reconciled   Boolean   @default(false)\n  reconciled_date DateTime?\n\n  transaction_date DateTime @default(now())\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  @@index([bank_account_id])\n  @@index([transaction_no])\n  @@index([transaction_date])\n  @@map(\"bank_transactions\")\n}\n\n/// Financial Forecasts\nmodel FinancialForecast {\n  id            String       @id @default(cuid())\n  forecast_name String\n  forecast_type ForecastType\n\n  fiscal_year  Int\n  period_start DateTime\n  period_end   DateTime\n\n  forecast_data Json\n\n  actual_data Json?\n\n  accuracy_score Float?\n  mape           Float?\n\n  model_type   String?\n  model_params Json?\n\n  status ForecastStatus @default(draft)\n\n  created_by String\n  notes      String?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([fiscal_year])\n  @@index([forecast_type])\n  @@index([status])\n  @@map(\"financial_forecasts\")\n}\n\n/// Financial Alerts\nmodel FinancialAlert {\n  id         String        @id @default(cuid())\n  alert_type AlertType\n  severity   AlertSeverity @default(medium)\n\n  title   String\n  message String\n\n  threshold_value Float?\n  current_value   Float?\n\n  status          AlertStatus @default(active)\n  acknowledged_by String?\n  acknowledged_at DateTime?\n  resolved_at     DateTime?\n\n  recipients Json\n\n  metadata Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([alert_type])\n  @@index([severity])\n  @@index([status])\n  @@map(\"financial_alerts\")\n}\n\n/// Tax Records\nmodel TaxRecord {\n  id         String  @id @default(cuid())\n  tax_type   TaxType\n  tax_period String\n\n  taxable_amount Float\n  tax_rate       Float\n  tax_amount     Float\n\n  status TaxStatus @default(pending)\n\n  filing_date DateTime?\n  due_date    DateTime\n  filed_by    String?\n\n  payment_status String @default(\"unpaid\")\n  paid_amount    Float  @default(0)\n\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tax_type])\n  @@index([tax_period])\n  @@index([status])\n  @@index([due_date])\n  @@map(\"tax_records\")\n}\n\n// ============================================================================\n// FINANCE ENHANCEMENT ENUMS\n// ============================================================================\n\nenum AccountType {\n  asset\n  liability\n  equity\n  revenue\n  expense\n\n  @@map(\"account_type\")\n}\n\nenum PeriodType {\n  monthly\n  quarterly\n  annually\n\n  @@map(\"period_type\")\n}\n\nenum BudgetStatus {\n  draft\n  submitted\n  approved\n  active\n  closed\n\n  @@map(\"budget_status\")\n}\n\nenum ARStatus {\n  outstanding\n  partial\n  paid\n  overdue\n  written_off\n\n  @@map(\"ar_status\")\n}\n\nenum APStatus {\n  outstanding\n  partial\n  paid\n  overdue\n\n  @@map(\"ap_status\")\n}\n\nenum BankAccountType {\n  checking\n  savings\n  credit_line\n  money_market\n\n  @@map(\"bank_account_type\")\n}\n\nenum ForecastType {\n  revenue\n  expense\n  cashflow\n  profit\n\n  @@map(\"forecast_type\")\n}\n\nenum ForecastStatus {\n  draft\n  active\n  archived\n\n  @@map(\"forecast_status\")\n}\n\nenum AlertType {\n  budget_exceeded\n  low_cash_balance\n  overdue_receivable\n  overdue_payable\n  unusual_transaction\n  forecast_deviation\n  compliance_issue\n\n  @@map(\"alert_type\")\n}\n\nenum AlertSeverity {\n  low\n  medium\n  high\n  critical\n\n  @@map(\"alert_severity\")\n}\n\nenum AlertStatus {\n  active\n  acknowledged\n  resolved\n  dismissed\n\n  @@map(\"alert_status\")\n}\n\nenum TaxType {\n  vat\n  income_tax\n  payroll_tax\n  withholding_tax\n  sales_tax\n\n  @@map(\"tax_type\")\n}\n\nenum TaxStatus {\n  pending\n  filed\n  paid\n  overdue\n\n  @@map(\"tax_status\")\n}\n\n// ============================================================================\n// HR & LEAVE MANAGEMENT MODELS\n// ============================================================================\n\n/// Types of Leave (e.g., Annual, Sick, Unpaid)\nmodel LeaveType {\n  id          String  @id @default(cuid())\n  name        String  @unique // e.g., \"Annual Leave\", \"Sick Leave\"\n  description String?\n  daysAllowed Int // Default days per year\n  carryOver   Boolean @default(false)\n\n  allocations LeaveAllocation[]\n  requests    LeaveRequest[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"leave_types\")\n}\n\n/// Leave Allocation - Tracks days allowed vs used per user per year\nmodel LeaveAllocation {\n  id          String    @id @default(cuid())\n  userId      String\n  user        User      @relation(fields: [userId], references: [id])\n  leaveTypeId String\n  leaveType   LeaveType @relation(fields: [leaveTypeId], references: [id])\n\n  year      Int // e.g., 2024\n  allocated Int // Total days given\n  used      Int @default(0) // Days consumed\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, leaveTypeId, year])\n  @@map(\"leave_allocations\")\n}\n\nenum LeaveStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  CANCELLED\n}\n\n/// Leave Requests\nmodel LeaveRequest {\n  id          String    @id @default(cuid())\n  userId      String\n  user        User      @relation(fields: [userId], references: [id])\n  leaveTypeId String\n  leaveType   LeaveType @relation(fields: [leaveTypeId], references: [id])\n\n  startDate DateTime\n  endDate   DateTime\n  days      Int // Calculated working days\n  reason    String?\n\n  status LeaveStatus @default(PENDING)\n\n  processedBy String? // User ID of approver/rejecter\n  processedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([status])\n  @@map(\"leave_requests\")\n}\n\n// ============================================================================\n// RECRUITMENT MODELS\n// ============================================================================\n\nenum JobPostingStatus {\n  DRAFT\n  PUBLISHED\n  CLOSED\n  ARCHIVED\n}\n\nmodel JobPosting {\n  id          String           @id @default(cuid())\n  title       String\n  description String\n  department  String\n  location    String?\n  type        String? // e.g., \"Full-time\", \"Contract\"\n  status      JobPostingStatus @default(DRAFT)\n\n  applicants Applicant[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"job_postings\")\n}\n\nenum ApplicantStatus {\n  NEW\n  REVIEWING\n  INTERVIEWING\n  OFFERED\n  HIRED\n  REJECTED\n}\n\nmodel Applicant {\n  id        String          @id @default(cuid())\n  name      String\n  email     String\n  phone     String?\n  resumeUrl String?\n  status    ApplicantStatus @default(NEW)\n  notes     String?\n\n  jobPostingId String\n  jobPosting   JobPosting @relation(fields: [jobPostingId], references: [id], onDelete: Cascade)\n\n  interviews Interview[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([jobPostingId])\n  @@map(\"applicants\")\n}\n\nenum InterviewStatus {\n  SCHEDULED\n  COMPLETED\n  CANCELLED\n}\n\nmodel Interview {\n  id            String    @id @default(cuid())\n  applicantId   String\n  applicant     Applicant @relation(fields: [applicantId], references: [id], onDelete: Cascade)\n  interviewerId String\n  interviewer   User      @relation(\"Interviewer\", fields: [interviewerId], references: [id])\n\n  scheduledAt DateTime\n  feedback    String?\n  rating      Int? // e.g., 1-5\n  status      InterviewStatus @default(SCHEDULED)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([applicantId])\n  @@index([interviewerId])\n  @@map(\"interviews\")\n}\n\n// ============================================================================\n// PERFORMANCE MODELS\n// ============================================================================\n\nenum PerformanceStatus {\n  NOT_STARTED\n  IN_PROGRESS\n  COMPLETED\n  OVERDUE\n}\n\nmodel Goal {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  title       String\n  description String?\n  targetDate  DateTime?\n  progress    Int               @default(0) // 0-100\n  status      PerformanceStatus @default(NOT_STARTED)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@map(\"performance_goals\")\n}\n\nmodel PerformanceEvaluation {\n  id          String @id @default(cuid())\n  userId      String\n  user        User   @relation(\"Evaluatee\", fields: [userId], references: [id])\n  evaluatorId String\n  evaluator   User   @relation(\"Evaluator\", fields: [evaluatorId], references: [id])\n\n  period   String // e.g., \"Q4 2024\", \"Annual 2024\"\n  date     DateTime @default(now())\n  ratings  Json? // Structured ratings for different competencies\n  comments String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([evaluatorId])\n  @@map(\"performance_evaluations\")\n}\n\nmodel DevelopmentPlan {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  title       String\n  description String\n  status      String @default(\"ACTIVE\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@map(\"development_plans\")\n}\n\n// ============================================================================\n// BENEFITS MODELS\n// ============================================================================\n\nmodel Benefit {\n  id          String  @id @default(cuid())\n  name        String\n  type        String // e.g., \"Health\", \"Dental\", \"Retirement\"\n  description String?\n  provider    String?\n\n  enrollments BenefitEnrollment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"benefits\")\n}\n\nmodel BenefitEnrollment {\n  id        String  @id @default(cuid())\n  userId    String\n  user      User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  benefitId String\n  benefit   Benefit @relation(fields: [benefitId], references: [id], onDelete: Cascade)\n\n  enrolledAt DateTime @default(now())\n  status     String   @default(\"ACTIVE\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, benefitId])\n  @@index([userId])\n  @@index([benefitId])\n  @@map(\"benefit_enrollments\")\n}\n\n// ============================================================================\n// RBAC MODELS\n// ============================================================================\n\nmodel Module {\n  id          String       @id @default(cuid())\n  name        String       @unique // e.g., \"Finance\", \"HR\"\n  code        String       @unique // e.g., \"finance\"\n  permissions Permission[]\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n\n  @@map(\"modules\")\n}\n\nmodel Permission {\n  id        String           @id @default(cuid())\n  name      String // e.g., \"Create Invoice\"\n  code      String           @unique // e.g., \"finance.invoice.create\"\n  moduleId  String\n  module    Module           @relation(fields: [moduleId], references: [id])\n  roles     RolePermission[]\n  createdAt DateTime         @default(now())\n  updatedAt DateTime         @updatedAt\n\n  @@index([moduleId])\n  @@map(\"permissions\")\n}\n\nmodel Role {\n  id          String           @id @default(cuid())\n  name        String           @unique // e.g., \"Finance Manager\"\n  code        String           @unique // e.g., \"finance_manager\"\n  description String?\n  isSystem    Boolean          @default(false) // Prevents deletion of core ERP roles\n  permissions RolePermission[]\n  users       RoleAssignment[]\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  @@map(\"roles\")\n}\n\nmodel RolePermission {\n  roleId       String\n  role         Role        @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  permissionId String\n  permission   Permission  @relation(fields: [permissionId], references: [id], onDelete: Cascade)\n  scope        AccessScope @default(BRANCH)\n\n  @@id([roleId, permissionId])\n  @@map(\"role_permissions\")\n}\n\nenum AccessScope {\n  GLOBAL\n  BRANCH\n  OWN\n}\n\nmodel RoleAssignment {\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  roleId String\n  role   Role   @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, roleId])\n  @@map(\"user_roles\")\n}\n\n// ============================================================================\n// AUDIT LOG MODEL\n// ============================================================================\n\nmodel AuditLog {\n  id         String      @id @default(cuid())\n  entityType String\n  entityId   String\n  action     AuditAction\n  userId     String?\n  user       User?       @relation(fields: [userId], references: [id], onDelete: SetNull)\n  changes    Json\n  ipAddress  String?\n  timestamp  DateTime    @default(now())\n\n  @@index([entityType, entityId])\n  @@index([userId])\n  @@index([timestamp])\n  @@map(\"audit_logs\")\n}\n"
}

